1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const ITEM_BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	};
29	
30	export function quote(input: QuoteInput): number {
31	  if (input.items.length === 0) return PROCESSING_FEE;
32	  const item = input.items[0];
33	  const itemBase = ITEM_BASE_PREMIUMS[item.type];
34	  const firstInsuranceSurcharge = itemBase * FIRST_INSURANCE_RATE;
35	  return itemBase + firstInsuranceSurcharge + PROCESSING_FEE;
36	}
