8	    expect(quote({ customer: { yearsWithMHPCO: 0, previousContracts: 0 }, items: [] })).toBe(5);
9	  });
10	
11	  // ===== Quote: single item base premiums (no modifiers, follow-up contract to neutralize first-insurance) =====
12	  // Use a long-standing customer's follow-up contract OR show base via integration.
13	  // We start with the simplest: single-item premiums combining base + first-insurance for a newcomer with no history.
14	  it("newcomer single sword (steel, enchantment 0, not cursed) yields premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
15	    expect(
16	      quote({
17	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
18	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
19	      })
20	    ).toBe(115);
