59	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
60	  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");
61	
62	  // ===== Quote: modifier scope on multi-item policies =====
63	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");
64	
65	  // ===== Quote: policy-wide modifiers =====
66	  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
67	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
68	  it.todo("follow-up contract gives 15% discount on policy base");
69	
70	  // ===== Quote: rounding in MHPCO's favor =====
71	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
72	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
73	
74	  // ===== Quote: integration examples from spec =====
75	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
