112	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
113	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
114	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
115	});
